/**
 * known/unknown/missing field keys vs the canonical registry.
 */
export type FieldManifestReconciliation = {
  known: string[];
  unknown: string[];
  missing: string[];
};

export type FieldManifestRelationshipCandidatesItem = {
  field: string;
  references: string;
  kind: string;
};

/**
 * The per-backend field manifest — the reconcile path made inspectable. Diffs the backend's describe against the canonical registry.
 */
export interface FieldManifest {
  mode: string;
  enumerated: DiscoveredField[];
  /** known/unknown/missing field keys vs the canonical registry. */
  reconciliation: FieldManifestReconciliation;
  customFields: DiscoveredField[];
  relationshipCandidates: FieldManifestRelationshipCandidatesItem[];
}

export type SettingsAiProvider = typeof SettingsAiProvider[keyof typeof SettingsAiProvider];


export const SettingsAiProvider = {
  none: 'none',
  openai: 'openai',
  ollama: 'ollama',
  anthropic: 'anthropic',
  openrouter: 'openrouter',
} as const;

/**
 * Speech-to-text engine. "browser" runs on-device (no audio egress); "whisper" is an AI-assisted, off-device transcription provider (governance-gated). "none" disables dictation server-side.
 */
export type SettingsSttProvider = typeof SettingsSttProvider[keyof typeof SettingsSttProvider];


export const SettingsSttProvider = {
  none: 'none',
  browser: 'browser',
  whisper: 'whisper',
} as const;

/**
 * Which FX rate consolidated reports convert at: "spot" (today's live rate), "periodClose" (the rate as of fxRateAsOfDate, e.g. the period the books closed at) or "budgetRate" (the rate as of fxRateAsOfDate treated as the rate the budget was set at, so variance isn't polluted by FX drift). A broker that can't serve a historical rate degrades to its live snapshot.
 */
export type SettingsFxRatePolicy = typeof SettingsFxRatePolicy[keyof typeof SettingsFxRatePolicy];


export const SettingsFxRatePolicy = {
  spot: 'spot',
  periodClose: 'periodClose',
  budgetRate: 'budgetRate',
} as const;

/**
 * Deployment context chosen in the setup wizard, which relaxes enterprise couplings by choice (e.g. a charity/self-hosted instance on a plain-HTTP LAN). Optional; absent until an admin selects one. The infra-level DEPLOYMENT_PROFILE env var takes precedence on a fresh boot (see docs/REVERSE-PROXY.md).
 */
export type SettingsDeploymentProfile = typeof SettingsDeploymentProfile[keyof typeof SettingsDeploymentProfile];


export const SettingsDeploymentProfile = {
  enterprise: 'enterprise',
  business: 'business',
  nonprofit: 'nonprofit',
  'self-hosted': 'self-hosted',
  demo: 'demo',
} as const;

export type FieldMapOverrideFields = {[key: string]: FieldSupport};

export type FieldMapOverrideEntities = {[key: string]: FieldSupport};

/**
 * Admin translation-layer overrides for the capability map. Each entry REPLACES that field's/entity's surface+store, correcting a mis-mapping.
 */
export interface FieldMapOverride {
  fields?: FieldMapOverrideFields;
  entities?: FieldMapOverrideEntities;
}

export interface Settings {
  /**
     * The active broker's webhook/endpoint URL.
     * @nullable
     */
  brokerUrl?: string | null;
  aiProvider: SettingsAiProvider;
  /** Speech-to-text engine. "browser" runs on-device (no audio egress); "whisper" is an AI-assisted, off-device transcription provider (governance-gated). "none" disables dictation server-side. */
  sttProvider?: SettingsSttProvider;
  /** @nullable */
  aiModel?: string | null;
  /** Free-form backend routing hint passed to the broker (e.g. "all", "jira", "azure-devops", "servicenow", "plane", "openproject"). "all" means no filter — whatever the broker is wired to. */
  backendSource: string;
  /**
     * ISO 4217 code the consolidated financial reports default to (e.g. "GBP"). Empty/absent ⇒ the FX table's base currency is used. Display-only — amounts are converted at view time via the broker FX rates; nothing is re-stored.
     * @nullable
     */
  reportingCurrency?: string | null;
  /** Which FX rate consolidated reports convert at: "spot" (today's live rate), "periodClose" (the rate as of fxRateAsOfDate, e.g. the period the books closed at) or "budgetRate" (the rate as of fxRateAsOfDate treated as the rate the budget was set at, so variance isn't polluted by FX drift). A broker that can't serve a historical rate degrades to its live snapshot. */
  fxRatePolicy?: SettingsFxRatePolicy;
  /**
     * ISO 8601 date the "as of" rate is read for when fxRatePolicy isn't "spot". Ignored (falls back to spot) when null.
     * @nullable
     */
  fxRateAsOfDate?: string | null;
  /** @nullable */
  oidcIssuerUrl?: string | null;
  /** Deployment context chosen in the setup wizard, which relaxes enterprise couplings by choice (e.g. a charity/self-hosted instance on a plain-HTTP LAN). Optional; absent until an admin selects one. The infra-level DEPLOYMENT_PROFILE env var takes precedence on a fresh boot (see docs/REVERSE-PROXY.md). */
  deploymentProfile?: SettingsDeploymentProfile;
  fieldOverrides?: FieldMapOverride;
}

